// MARK: - Security Manager
class SecurityManager {
    static let shared = SecurityManager()
    private let keychain = KeychainManager()
    
    private init() {}
    
    func encryptData(_ data: Data) throws -> Data {
        guard let key = keychain.getEncryptionKey() else {
            throw SecurityError.keyNotFound
        }
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw SecurityError.encryptionFailed
        }
        return combined
    }
    
    func decryptData(_ data: Data) throws -> Data {
        guard let key = keychain.getEncryptionKey() else {
            throw SecurityError.keyNotFound
        }
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        return try AES.GCM.open(sealedBox, using: key)
    }
    
    func generateAPISignature(payload: String, timestamp: String) -> String {
        guard let apiSecret = keychain.getAPISecret() else { return "" }
        let message = "\(timestamp)\(payload)"
        let key = SymmetricKey(data: Data(apiSecret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(message.utf8), using: key)
        return Data(signature).base64EncodedString()
    }
}

enum SecurityError: Error {
    case keyNotFound
    case encryptionFailed
    case decryptionFailed
}

// MARK: - Keychain Manager
class KeychainManager {
    func getEncryptionKey() -> SymmetricKey? {
        if let keyData = getKeychainData(key: "encryptionKey") {
            return SymmetricKey(data: keyData)
        }
        let newKey = SymmetricKey(size: .bits256)
        let keyData = newKey.withUnsafeBytes { Data($0) }
        saveKeychainData(key: "encryptionKey", data: keyData)
        return newKey
    }
    
    func getAPISecret() -> String? {
        guard let data = getKeychainData(key: "apiSecret") else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func saveAPICredentials(apiKey: String, apiSecret: String) {
        saveKeychainData(key: "apiKey", data: Data(apiKey.utf8))
        saveKeychainData(key: "apiSecret", data: Data(apiSecret.utf8))
    }
    
    func getAPIKey() -> String? {
        guard let data = getKeychainData(key: "apiKey") else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    private func saveKeychainData(key: String, data: Data) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    private func getKeychainData(key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true
        ]
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        return status == errSecSuccess ? result as? Data : nil
    }
}

