class PortfolioService {
    static let shared = PortfolioService()
    private let networkManager = NetworkManager.shared
    
    private init() {}
    
    func getPortfolio() async throws -> Portfolio {
        let response: APIResponse<Portfolio> = try await networkManager.request(endpoint: "/portfolio")
        guard let portfolio = response.data else {
            throw PortfolioError.fetchFailed
        }
        return portfolio
    }
    
    func getHoldings() async throws -> [Holding] {
        let response: APIResponse<[Holding]> = try await networkManager.request(endpoint: "/portfolio/holdings")
        return response.data ?? []
    }
    
    func validateTrade(symbol: String, type: TradeType, quantity: Int, price: Decimal) async throws -> Bool {
        let portfolio = try await getPortfolio()
        
        switch type {
        case .buy:
            let totalCost = price * Decimal(quantity)
            return portfolio.cashBalance >= totalCost
        case .sell:
            if let holding = portfolio.holdings.first(where: { $0.symbol == symbol }) {
                return holding.quantity >= quantity
            }
            return false
        }
    }
