// MARK: - Market Data Service
class MarketDataService {
    static let shared = MarketDataService()
    private let networkManager = NetworkManager.shared
    private var webSocketTask: URLSessionWebSocketTask?
    private var priceUpdateSubject = PassthroughSubject<Stock, Never>()
    
    var priceUpdates: AnyPublisher<Stock, Never> {
        priceUpdateSubject.eraseToAnyPublisher()
    }
    
    func getStockQuote(symbol: String) async throws -> Stock {
        let response: APIResponse<Stock> = try await networkManager.request(endpoint: "/quotes/\(symbol)")
        guard let stock = response.data else {
            throw MarketDataError.quoteFetchFailed
        }
        return stock
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        let response: APIResponse<[Stock]> = try await networkManager.request(endpoint: "/search?q=\(query)")
        return response.data ?? []
    }
    
    func subscribeToRealTimeUpdates(symbols: [String]) {
        guard let url = URL(string: "wss://api.tradingplatform.com/v1/stream") else { return }
        
        var request = URLRequest(url: url)
        if let apiKey = KeychainManager().getAPIKey() {
            request.setValue(apiKey, forHTTPHeaderField: "X-API-Key")
        }
        
        webSocketTask = URLSession.shared.webSocketTask(with: request)
        webSocketTask?.resume()
        
        let subscribeMessage = ["action": "subscribe", "symbols": symbols] as [String : Any]
        if let data = try? JSONSerialization.data(withJSONObject: subscribeMessage),
           let message = String(data: data, encoding: .utf8) {
            webSocketTask?.send(.string(message)) { _ in }
        }
        
        receiveMessage()
    }
    
    private func receiveMessage() {
        webSocketTask?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    if let data = text.data(using: .utf8),
                       let stock = try? JSONDecoder().decode(Stock.self, from: data) {
                        self?.priceUpdateSubject.send(stock)
                    }
                case .data(let data):
                    if let stock = try? JSONDecoder().decode(Stock.self, from: data) {
                        self?.priceUpdateSubject.send(stock)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
            case .failure:
                break
            }
        }
    }
    
    func unsubscribe() {
        webSocketTask?.cancel(with: .goingAway, reason: nil)
        webSocketTask = nil
    }
}

enum MarketDataError: Error {
    case quoteFetchFailed
    case connectionFailed
}

// MARK: - View Models
class TradingViewModel: ObservableObject {
    @Published var selectedStock: Stock?
    @Published var quantity: String = ""
    @Published var limitPrice: String = ""
    @Published var orderType: OrderType = .market
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var successMessage: String?
    
    private let tradingService = TradingService.shared
    private let portfolioService = PortfolioService.shared
    
    func executeTrade(type: TradeType) async {
        guard let stock = selectedStock,
              let qty = Int(quantity), qty > 0 else {
            await MainActor.run {
                errorMessage = "Invalid quantity"
            }
            return
        }
        
        await MainActor.run {
            isLoading = true
            errorMessage = nil
        }
        
        do {
            let price = orderType == .limit ? Decimal(string: limitPrice) ?? stock.currentPrice : stock.currentPrice
            
            let canTrade = try await portfolioService.validateTrade(
                symbol: stock.symbol,
                type: type,
                quantity: qty,
                price: price
            )
            
            guard canTrade else {
                await MainActor.run {
                    errorMessage = type == .buy ? "Insufficient funds" : "Insufficient shares"
                    isLoading = false
                }
                return
            }
            
            let trade: Trade
            if orderType == .market {
                trade = try await tradingService.executeMarketOrder(symbol: stock.symbol, type: type, quantity: qty)
            } else {
                guard let limit = Decimal(string: limitPrice) else {
                    await MainActor.run {
                        errorMessage = "Invalid limit price"
                        isLoading = false
                    }
                    return
                }
                trade = try await tradingService.executeLimitOrder(symbol: stock.symbol, type: type, quantity: qty, limitPrice: limit)
            }
            
            await MainActor.run {
                successMessage = "Order placed successfully: \(trade.id)"
                quantity = ""
                limitPrice = ""
                isLoading = false
            }
        } catch {
            await MainActor.run {
                errorMessage = error.localizedDescription
                isLoading = false
            }
        }
    }
}

