class MarketViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var searchResults: [Stock] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private let marketDataService = MarketDataService.shared
    private var cancellables = Set<AnyCancellable>()
    
    init() {
        marketDataService.priceUpdates
            .receive(on: DispatchQueue.main)
            .sink { [weak self] updatedStock in
                self?.updateStock(updatedStock)
            }
            .store(in: &cancellables)
    }
    
    func searchStocks(query: String) async {
        guard !query.isEmpty else {
            await MainActor.run {
                searchResults = []
            }
            return
        }
        
        await MainActor.run {
            isLoading = true
        }
        
        do {
            let results = try await marketDataService.searchStocks(query: query)
            await MainActor.run {
                searchResults = results
                isLoading = false
            }
        } catch {
            await MainActor.run {
                errorMessage = error.localizedDescription
                isLoading = false
            }
        }
    }
    
    func loadStock(symbol: String) async -> Stock? {
        do {
            return try await marketDataService.getStockQuote(symbol: symbol)
        } catch {
            await MainActor.run {
                errorMessage = error.localizedDescription
            }
            return nil
        }
    }
    
    func subscribeToUpdates(symbols: [String]) {
        marketDataService.subscribeToRealTimeUpdates(symbols: symbols)
    }
    
    private func updateStock(_ updatedStock: Stock) {
        if let index = stocks.firstIndex(where: { $0.id == updatedStock.id }) {
            stocks[index] = updatedStock
        }
    }
}

