        orderTypeSegment.addTarget(self, action: #selector(orderTypeChanged), for: .valueChanged)
        
        buyButton.setTitle("Buy", for: .normal)
        buyButton.backgroundColor = .systemGreen
        buyButton.setTitleColor(.white, for: .normal)
