            stockSymbolLabel, currentPriceLabel, quantityTextField,
            orderTypeSegment, limitPriceTextField, buyButton, sellButton
        ])
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        view.addSubview(activityIndicator)
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        
        NSLayoutConstraint.activate([
            stackView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            buyButton.heightAnchor.constraint(equalToConstant: 50),
            sellButton.heightAnchor.constraint(equalToConstant: 50),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    private func setupBindings() {
        viewModel.$selectedStock
            .receive(on: DispatchQueue.main)
            .sink { [weak self] stock in
                self?.stockSymbolLabel.text = stock?.symbol ?? ""
                if let price = stock?.currentPrice {
                    self?.currentPriceLabel.text = "$\(price)"
                }
            }
            .store(in: &cancellables)
        
        viewModel.$isLoading
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isLoading in
                if isLoading {
                    self?.activityIndicator.startAnimating()
                    self?.buyButton.isEnabled = false
                    self?.sellButton.isEnabled = false
                } else {
                    self?.activityIndicator.stopAnimating()
                    self?.buyButton.isEnabled = true
                    self?.sellButton.isEnabled = true
                }
            }
            .store(in: &cancellables)
        
        viewModel.$errorMessage
            .receive(on: DispatchQueue.main)
            .sink { [weak self] message in
                if let message = message {
                    self?.showAlert(title: "Error", message: message)
                }
            }
            .store(in: &cancellables)
        
        viewModel.$successMessage
            .receive(on: DispatchQueue.main)
            .sink { [weak self] message in
                if let message = message {
                    self?.showAlert(title: "Success", message: message)
                }
            }
            .store(in: &cancellables)
    }
    
    @objc private func orderTypeChanged() {
        let isLimit = orderTypeSegment.selectedSegmentIndex == 1
        limitPriceTextField.isHidden = !isLimit
        viewModel.orderType = isLimit ? .limit : .market
    }
    
    @objc private func buyTapped() {
        viewModel.quantity = quantityTextField.text ?? ""
        viewModel.limitPrice = limitPriceTextField.text ?? ""
        Task {
            await viewModel.executeTrade(type: .buy)
        }
    }
    
    @objc private func sellTapped() {
        viewModel.quantity = quantityTextField.text ?? ""
        viewModel.limitPrice = limitPriceTextField.text ?? ""
        Task {
            await viewModel.executeTrade(type: .sell)
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    func configure(with stock: Stock) {
        viewModel.selectedStock = stock
    }
}

