}

extension PortfolioViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return viewModel.portfolio?.holdings.count ?? 0
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "HoldingCell", for: indexPath) as! HoldingCell
        if let holding = viewModel.portfolio?.holdings[indexPath.row] {
            cell.configure(with: holding)
        }
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        if let holding = viewModel.portfolio?.holdings[indexPath.row] {
            let tradingVC = TradingViewController()
            Task {
                if let stock = await MarketViewModel().loadStock(symbol: holding.symbol) {
                    tradingVC.configure(with: stock)
                    navigationController?.pushViewController(tradingVC, animated: true)
                }
            }
        }
    }
}

class HoldingCell: UITableViewCell {
    private let symbolLabel = UILabel()
    private let quantityLabel = UILabel()
    private let valueLabel = UILabel()
    private let gainLossLabel = UILabel()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupUI()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupUI() {
        symbolLabel.font = .systemFont(ofSize: 18, weight: .semibold)
        quantityLabel.font = .systemFont(ofSize: 14)
        quantityLabel.textColor = .secondaryLabel
        valueLabel.font = .systemFont(ofSize: 16, weight: .medium)
        valueLabel.textAlignment = .right
        gainLossLabel.font = .systemFont(ofSize: 14)
        gainLossLabel.textAlignment = .right
        
        let leftStack = UIStackView(arrangedSubviews: [symbolLabel, quantityLabel])
        leftStack.axis = .vertical
        leftStack.spacing = 4
        
        let rightStack = UIStackView(arrangedSubviews: [valueLabel, gainLossLabel])
        rightStack.axis = .vertical
        rightStack.spacing = 4
        rightStack.alignment = .trailing
        
        let mainStack = UIStackView(arrangedSubviews: [leftStack, rightStack])
        mainStack.axis = .horizontal
        mainStack.distribution = .equalSpacing
        mainStack.translatesAutoresizingMaskIntoConstraints = false
        
        contentView.addSubview(mainStack)
        
        NSLayoutConstraint.activate([
            mainStack.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            mainStack.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            mainStack.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            mainStack.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -12)
        ])
    }
    
    func configure(with holding: Holding) {
        symbolLabel.text = holding.symbol
        quantityLabel.text = "\(holding.quantity) shares @ $\(holding.averagePrice)"
        valueLabel.text = "$\(holding.totalValue)"
        gainLossLabel.text = "$\(holding.gainLoss) (\(holding.gainLossPercent)%)"
        gainLossLabel.textColor = holding.gainLoss >= 0 ? .systemGreen : .systemRed
    }
}

class MarketViewController: UIViewController {
    private let viewModel = MarketViewModel()
    private var cancellables = Set<AnyCancellable>()
    
    private let searchController = UISearchController(searchResultsController: nil)
    private let tableView = UITableView()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupBindings()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Market"
        
        searchController.searchResultsUpdater = self
        searchController.obscuresBackgroundDuringPresentation = false
        searchController.searchBar.placeholder = "Search stocks"
        navigationItem.searchController = searchController
        definesPresentationContext = true
        
        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.register(StockCell.self, forCellReuseIdentifier: "StockCell")
        tableView.dataSource = self
        tableView.delegate = self
        
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    private func setupBindings() {
        viewModel.$searchResults
            .receive(on: DispatchQueue.main)
            .sink { [weak self] _ in
                self?.tableView.reloadData()
            }
            .store(in: &cancellables)
    }
}

extension MarketViewController: UISearchResultsUpdating {
    func updateSearchResults(for searchController: UISearchController) {
        guard let query = searchController.searchBar.text else { return }
        Task {
            await viewModel.searchStocks(query: query)
        }
    }
}

extension MarketViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return viewModel.searchResults.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "StockCell", for: indexPath) as! StockCell
        let stock = viewModel.searchResults[indexPath.row]
        cell.configure(with: stock)
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let stock = viewModel.searchResults[indexPath.row]
        let tradingVC = TradingViewController()
        tradingVC.configure(with: stock)
        navigationController?.pushViewController(tradingVC, animated: true)
    }
}

