// MARK: - App Delegate
@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        window = UIWindow(frame: UIScreen.main.bounds)
        
        let marketVC = MarketViewController()
        let portfolioVC = PortfolioViewController()
        
        let marketNav = UINavigationController(rootViewController: marketVC)
        marketNav.tabBarItem = UITabBarItem(title: "Market", image: UIImage(systemName: "chart.line.uptrend.xyaxis"), tag: 0)
        
        let portfolioNav = UINavigationController(rootViewController: portfolioVC)
        portfolioNav.tabBarItem = UITabBarItem(title: "Portfolio", image: UIImage(systemName: "briefcase"), tag: 1)
        
        let tabBarController = UITabBarController()
        tabBarController.viewControllers = [marketNav, portfolioNav]
        
        window?.rootViewController = tabBarController
        window?.makeKeyAndVisible()
        
        return true
    }
}